import java.io.IOException;
import java.io.PrintWriter;

import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class XSSSecureCode {

    public static void main(String[] args) {
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly escape user input
        String safeInput = "";
        try {
            safeInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            e.printStackTrace();
        }

        String output = "<div>" + safeInput + "</div";

        try {
            PrintWriter out = new PrintWriter("output.html");
            out.println(output);
            out.close();
            System.out.println("Output written to output.html");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
